__kernel void compute_distances(
    __global const char* sandbox,
    __global float* z,
    const float target_lat,
    const float target_long,
    const int rec_count)
{
    int i = get_global_id(0);
    if (i < rec_count) {
        int base_idx = i * 49 + 27; // LATITUDE_POS - 1 = 27
        // Extract latitude string (5 chars)
        char lat_str[8];
        for (int c = 0; c < 7; c++) {
            lat_str[c] = sandbox[base_idx + c];
        }
        lat_str[7] = '\0';

        // Extract longitude string (5 chars)
        char long_str[8];
        for (int c = 0; c < 7; c++) {
            long_str[c] = sandbox[base_idx + 7 + c];
        }
        long_str[7] = '\0';

        // Simple atof for lat_str
        float tmp_lat = 0.0f;
        int sign = 1;
        int idx = 0;
        if (lat_str[0] == '-') {
            sign = -1;
            idx = 1;
        }
        float int_part = 0.0f;
        while (lat_str[idx] >= '0' && lat_str[idx] <= '9') {
            int_part = int_part * 10.0f + (lat_str[idx] - '0');
            idx++;
        }
        float frac_part = 0.0f;
        float divisor = 10.0f;
        if (lat_str[idx] == '.') {
            idx++;
            while (lat_str[idx] >= '0' && lat_str[idx] <= '9') {
                frac_part += (lat_str[idx] - '0') / divisor;
                divisor *= 10.0f;
                idx++;
            }
        }
        tmp_lat = sign * (int_part + frac_part);

        // Simple atof for long_str
        float tmp_long = 0.0f;
        sign = 1;
        idx = 0;
        if (long_str[0] == '-') {
            sign = -1;
            idx = 1;
        }
        int_part = 0.0f;
        while (long_str[idx] >= '0' && long_str[idx] <= '9') {
            int_part = int_part * 10.0f + (long_str[idx] - '0');
            idx++;
        }
        frac_part = 0.0f;
        divisor = 10.0f;
        if (long_str[idx] == '.') {
            idx++;
            while (long_str[idx] >= '0' && long_str[idx] <= '9') {
                frac_part += (long_str[idx] - '0') / divisor;
                divisor *= 10.0f;
                idx++;
            }
        }
        tmp_long = sign * (int_part + frac_part);

        float diff_lat = tmp_lat - target_lat;
        float diff_long = tmp_long - target_long;
        z[i] = sqrt(diff_lat * diff_lat + diff_long * diff_long);
    }
}
